struct AnalyticsLogger {
    static let shared = AnalyticsLogger()
    private let logQueue = DispatchQueue(label: "analytics.logger.queue", qos: .background)
    
    private init() {}
    
    func logEvent(_ event: AnalyticsEvent, data: [String: Any] = [:], userId: String? = nil) {
        logQueue.async {
            let timestamp = Date().ISO8601Format()
            var logData = [
                "timestamp": timestamp,
                "event": event.rawValue,
                "user_id": userId ?? "anonymous"
            ] as [String: Any]
            
            for (key, value) in data {
                if let stringValue = value as? String {
                    if self.isSensitive(key: key, value: stringValue) {
                        logData[key] = "[REDACTED]"
                    } else {
                        logData[key] = value
                    }
                } else {
                    logData[key] = value
                }
            }
            
            let logMessage = self.formatLogMessage(logData)
            self.writeToLog(logMessage)
        }
    }
    
    private func isSensitive(key: String, value: String) -> Bool {
        let sensitiveKeys = ["email", "token", "password", "secret", "auth", "credential"]
        let sensitiveWords = ["token", "password", "secret", "auth", "credential"]
        
        let lowerKey = key.lowercased()
        let lowerValue = value.lowercased()
        
        for sensitiveKey in sensitiveKeys {
            if lowerKey.contains(sensitiveKey) {
                return true
            }
        }
        
        for sensitiveWord in sensitiveWords {
            if lowerValue.contains(sensitiveWord) {
                return true
            }
        }
        
        return false
    }
    
    private func formatLogMessage(_ data: [String: Any]) -> String {
        var message = ""
        for (key, value) in data {
            if let arrayValue = value as? [Any] {
                message += "\(key): [\(arrayValue.count) items], "
            } else if let dictValue = value as? [String: Any] {
                message += "\(key): { \(dictValue.count) items }, "
            } else {
                message += "\(key): \(value), "
            }
        }
        return message.trimmingCharacters(in: CharacterSet(charactersIn: ", "))
    }
    
    private func writeToLog(_ message: String) {
        let logString = "[Analytics] \(message)"
        NSLog("%@", logString)
        print(logString)
        
        // Write to file for additional debugging
        writeToFile(logString)
    }
    
    private func writeToFile(_ message: String) {
        guard let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first else { return }
        
        let logFileURL = documentsPath.appendingPathComponent("analytics.log")
        
        let logEntry = "\(Date().ISO8601Format()): \(message)\n"
        
        do {
            if FileManager.default.fileExists(atPath: logFileURL.path) {
                try logEntry.write(to: logFileURL, atomically: true, encoding: .utf8)
            } else {
                try logEntry.write(to: logFileURL, atomically: true, encoding: .utf8)
            }
        } catch {
            NSLog("Failed to write to analytics log file: %@", error.localizedDescription)
        }
    }
